          "hackathonRP2023": { "title": "Hackathon 3D Slicer de três dias, 8-10 out. de 2023, Ribeirão Preto, Brasil", "description": "A equipe brasileira organizou um Hackathon 3D Slicer de três dias dentro da programação do <a href=\"https://www.xisiim2023.com/\" class=\"hyperlink\">XI Simpósio de Imagens e Instrumentação Médica</a>, realizado de 8 a 10 de outubro de 2023, na Universidade de São Paulo, campus de Ribeirão Preto." },
          "pw39": { "title": "39ª Semana de Projetos Slicer (PW39), 12-16 jun. de 2023, Montreal, Canadá", "description": "A <a href=\"PW39_2023_Montreal.html\" class=\"hyperlink\">39ª Semana de Projetos Slicer</a> foi realizada de 12 a 16 de junho de 2023, na École de Technologie Supérieure, Montreal, Canadá. A equipe participou com o <a href=\"https://projectweek.na-mic.org/PW39_2023_Montreal/Projects/3DSlicerForLatinAmerica/\" class=\"hyperlink\">projeto 3D Slicer para a América Latina</a>, avançando no desenvolvimento do Tutorial Maker e na localização do Slicer." },
          "pw38": { "title": "38ª Semana de Projetos Slicer (PW38), 30 jan. - 3 fev. de 2023, Las Palmas, Gran Canária, Espanha", "description": "A <a href=\"PW38_2023_GranCanaria.html\" class=\"hyperlink\">38ª Semana de Projetos Slicer</a> foi realizada de 30 de janeiro a 3 de fevereiro de 2023, em Las Palmas, Gran Canária, Espanha. A Dra. Sonia Pujol conduziu sessões online diárias sobre internacionalização do 3D Slicer e apresentou o projeto \"3D Slicer para a América Latina: Localização e Divulgação\" à comunidade 3D Slicer no evento. A Dra. Adriana Vilchis González e o Dr. Luiz Murta participaram das sessões diárias que reuniram 23 participantes do México, Brasil, Senegal, Hungria, Mauritânia, EUA e Canadá. A Dra. Pujol ministrou um tutorial de treinamento sobre como usar a infraestrutura de internacionalização do 3D Slicer para traduzir o programa para múltiplos idiomas. Os membros da equipe latino-americana contribuíram para o <a href=\"https://projectweek.na-mic.org/PW38_2023_GranCanaria/Projects/3DSlicerInternationalization/\" class=\"hyperlink\">projeto de Internacionalização do 3D Slicer</a>." },
          "rsna2022": { "title": "108ª Reunião Anual da Radiological Society of North America (RSNA 2022), 27 nov. - 1 dez. de 2022, Chicago, IL, EUA", "description": "Apresentamos o projeto \"3D Slicer para a América Latina: Localização e Divulgação\" em nosso expositor educacional intitulado \"A plataforma de software de código aberto 3D Slicer para processamento de imagens médicas, visualização 3D e terapia guiada por imagem\" (Sonia Pujol, PhD, Steve Pieper, PhD, Andras Lasso, PhD, Andriy Fedorov, PhD, Ron Kikinis, MD) na 108ª Reunião Anual da RSNA 2022." },
