      "work": {
        "pageTitle": "Tutorial Maker",
        "description": { "title": "Descrição", "p1": "O Tutorial Maker é uma ferramenta para automatizar a criação de tutoriais dentro do ambiente 3D Slicer. Para atingir esse objetivo, foi implementada uma metodologia de gerenciamento de projetos que combina reuniões virtuais semanais e o uso da plataforma GitHub como sistema de controle de versão para desenvolvimento de código e colaboração.", "p2": "Esta ferramenta foi desenvolvida pela <b>equipe do 3D Slicer para a América Latina</b>, cujos membros fizeram progressos significativos no desenvolvimento do Módulo Tutorial Maker, com foco em melhorar sua funcionalidade, usabilidade e acessibilidade." },
        "objectives": { "title": "Objetivos", "intro": "Entre os objetivos da ferramenta Tutorial Maker estão os seguintes:", "internationalization": "Internacionalização:", "internationalizationDesc": "As strings da interface de usuário do módulo foram marcadas, permitindo tradução fácil para múltiplos idiomas. As etapas de instalação do módulo em espanhol, português e inglês estão documentadas.", "accessibility": "Acessibilidade:", "accessibilityDesc": "Uma instalação e uso simplificados do módulo permite que uma gama mais ampla de usuários se beneficie da ferramenta.", "flexibility": "Flexibilidade na Criação de Conteúdo:", "flexibilityDesc": "A possibilidade de gerar tutoriais em múltiplos formatos amplia as possibilidades de distribuição e utilização do conteúdo criado.", "userExperience": "Experiência do Usuário Aprimorada:", "userExperienceDesc": "Otimizações de interface e novos recursos tornam o processo de criação de tutoriais mais intuitivo e eficiente.", "sustainability": "Sustentabilidade do Projeto:", "sustainabilityDesc": "A automação de processos e a melhoria do gerenciamento de projetos garantem o desenvolvimento contínuo e a manutenção de longo prazo do módulo." },
        "features": { "title": "Funcionalidades", "automatedTitle": "Geração Automatizada de Tutoriais", "automatedDesc": "Simplifica a criação de tutoriais do 3D Slicer executando fluxos de trabalho automaticamente e capturando capturas de tela para cada etapa, reduzindo o esforço manual.", "annotationTitle": "Ferramentas de Anotação Integradas", "annotationDesc": "Inclui um editor integrado para adicionar setas, caixas de texto, destaques e outras dicas visuais diretamente nas capturas de tela do tutorial, melhorando a clareza.", "exportTitle": "Opções de Exportação Flexíveis", "exportDesc": "Permite aos usuários salvar capturas de tela anotadas e gerar conteúdo adequado para vários formatos de documentação (HTML, PDF, Markdown).", "multiLangTitle": "Suporte a Múltiplos Idiomas", "multiLangDesc": "Projetado para facilitar a criação e a localização de tutoriais em múltiplos idiomas (incluindo inglês, espanhol, português e francês), tornando o Slicer acessível a um público mais amplo." },
        "repository": { "title": "Repositório", "description": "<a href=\"https://github.com/SoniaPujolLab/SlicerTutorialMaker\" class=\"hyperlink\" target=\"_blank\">O repositório da ferramenta Tutorial Maker</a> contém um processo de instalação passo a passo e é constantemente atualizado de acordo com as melhorias introduzidas pela equipe." },
        "collection": { "title": "Coleção Slicer Tutorial Maker", "description": "A <a href=\"tutorial-collection.html\" class=\"hyperlink\">Coleção Slicer Tutorial Maker</a> apresenta tutoriais criados com a extensão Tutorial Maker, cobrindo tópicos desde a navegação básica no 3D Slicer até a segmentação baseada em IA." },
        "localization": { "title": "Localização", "description": "A <a href=\"localization.html\" class=\"hyperlink\">página de Localização</a> contém os tutoriais traduzidos (português e espanhol) e as versões originais em inglês." }
      },
      "localization": { "pageTitle": "Localização", "intro": "Como parte do projeto 3D Slicer para a América Latina, 14 tutoriais foram localizados manualmente para o espanhol latino-americano e o português brasileiro. Os tutoriais são apresentados abaixo, incluindo as versões originais em inglês para referência.", "versionLabel": "Versão", "glossary": { "title": "Glossário Localizado", "intro": "Os glossários a seguir fornecem terminologia localizada para o 3D Slicer em espanhol latino-americano e português brasileiro.", "viewGlossary": "Ver Glossário" }, "langs": { "english": "Inglês", "portugueseBR": "Português (BR)", "spanishLA": "Espanhol (América Latina)" } },
      "tutorialCollection": {
        "pageTitle": "Coleção Slicer Tutorial Maker",
        "intro": "A <strong>Coleção Slicer Tutorial Maker</strong> é um conjunto selecionado de tutoriais criados com a extensão <a href=\"https://github.com/SoniaPujolLab/SlicerTutorialMaker\" class=\"hyperlink\" target=\"_blank\">Slicer Tutorial Maker</a>. Cada tutorial é gerado automaticamente pela execução de um script Python dentro do 3D Slicer, que captura capturas de tela anotadas e produz saídas nos formatos HTML, PDF e Markdown. Os tutoriais estão disponíveis em múltiplos idiomas e servem tanto como recursos de aprendizagem quanto como implementações de referência para autores que criam novos tutoriais.",
        "loading": "Carregando\u2026", "noLanguages": "Nenhum idioma disponível.", "viewOnGitHub": "Ver no GitHub",
        "cards": { "welcome": { "title": "Tutorial de Boas-vindas", "li1": "Introdução à interface do 3D Slicer", "li2": "Carregamento e exploração de dados de amostra", "li3": "Navegação nas vistas 3D e 2D", "li4": "Ponto de partida ideal para usuários iniciantes" }, "fourMinute": { "title": "Tutorial de Quatro Minutos", "li1": "Visão geral rápida dos recursos principais do Slicer", "li2": "Carregamento de dados e visualização básica", "li3": "Interação básica com o usuário", "li4": "Comece em menos de 4 minutos" }, "aiSegmentation": { "title": "Segmentação Baseada em IA no 3D Slicer", "li1": "Segmentação anatômica com IA", "li2": "Carregamento e processamento de dados DICOM", "li3": "Geração de modelos de segmentação 3D", "li4": "Fluxo de trabalho completo de ponta a ponta" }, "visualization": { "title": "Tutorial de Carregamento de Dados e Visualização 3D", "li1": "Visualização 3D interativa", "li2": "Recorte interativo de dados", "li3": "Manipulação interativa da viewport", "li4": "Apresentação de dados de imagens médicas" } }
      },
