      "work": {
        "pageTitle": "Tutorial Maker",
        "description": { "title": "Descripción", "p1": "El Tutorial Maker es una herramienta para automatizar la creación de tutoriales dentro del entorno 3D Slicer. Para lograr este objetivo, se ha implementado una metodología de gestión de proyectos que combina reuniones virtuales semanales y el uso de la plataforma GitHub como sistema de control de versiones para el desarrollo de código y la colaboración.", "p2": "Esta herramienta fue desarrollada por el <b>equipo del 3D Slicer para América Latina</b>, cuyos miembros han logrado avances significativos en el desarrollo del Módulo Tutorial Maker, enfocándose en mejorar su funcionalidad, usabilidad y accesibilidad." },
        "objectives": { "title": "Objetivos", "intro": "Entre los objetivos de la herramienta Tutorial Maker se encuentran los siguientes:", "internationalization": "Internacionalización:", "internationalizationDesc": "Las cadenas de texto de la interfaz de usuario del módulo fueron marcadas, lo que permite su fácil traducción a múltiples idiomas. Los pasos de instalación del módulo en español, portugués e inglés están documentados.", "accessibility": "Accesibilidad:", "accessibilityDesc": "Una instalación y uso simplificados del módulo permite que un mayor número de usuarios se beneficien de la herramienta.", "flexibility": "Flexibilidad en la Creación de Contenido:", "flexibilityDesc": "La posibilidad de generar tutoriales en múltiples formatos amplía las posibilidades de distribución y utilización del contenido creado.", "userExperience": "Experiencia de Usuario Mejorada:", "userExperienceDesc": "Las optimizaciones de la interfaz y las nuevas funciones hacen que el proceso de creación de tutoriales sea más intuitivo y eficiente.", "sustainability": "Sostenibilidad del Proyecto:", "sustainabilityDesc": "La automatización de procesos y la mejora en la gestión del proyecto garantizan el desarrollo continuo y el mantenimiento a largo plazo del módulo." },
        "features": { "title": "Características", "automatedTitle": "Generación Automatizada de Tutoriales", "automatedDesc": "Simplifica la creación de tutoriales del 3D Slicer ejecutando flujos de trabajo automáticamente y capturando capturas de pantalla para cada paso, reduciendo el esfuerzo manual.", "annotationTitle": "Herramientas de Anotación Integradas", "annotationDesc": "Incluye un editor incorporado para agregar flechas, cuadros de texto, resaltados y otras pistas visuales directamente sobre las capturas de pantalla del tutorial, mejorando la claridad.", "exportTitle": "Opciones de Exportación Flexibles", "exportDesc": "Permite a los usuarios guardar capturas de pantalla anotadas y generar contenido adecuado para varios formatos de documentación (HTML, PDF, Markdown).", "multiLangTitle": "Soporte Multilingüe", "multiLangDesc": "Diseñado para facilitar la creación y localización de tutoriales en múltiples idiomas (incluidos inglés, español, portugués y francés), haciendo que Slicer sea accesible a un público más amplio." },
        "repository": { "title": "Repositorio", "description": "<a href=\"https://github.com/SoniaPujolLab/SlicerTutorialMaker\" class=\"hyperlink\" target=\"_blank\">El repositorio de la herramienta Tutorial Maker</a> contiene un proceso de instalación paso a paso y se actualiza constantemente de acuerdo con las mejoras introducidas por el equipo." },
        "collection": { "title": "Colección Slicer Tutorial Maker", "description": "La <a href=\"tutorial-collection.html\" class=\"hyperlink\">Colección Slicer Tutorial Maker</a> presenta tutoriales creados con la extensión Tutorial Maker, que cubren temas desde la navegación básica en 3D Slicer hasta la segmentación basada en IA." },
        "localization": { "title": "Localización", "description": "La <a href=\"localization.html\" class=\"hyperlink\">página de Localización</a> contiene los tutoriales traducidos (portugués y español) y las versiones originales en inglés." }
      },
      "localization": { "pageTitle": "Localización", "intro": "Como parte del proyecto 3D Slicer para América Latina, 14 tutoriales fueron localizados manualmente al español latinoamericano y al portugués brasileño. Los tutoriales se presentan a continuación, incluyendo las versiones originales en inglés como referencia.", "versionLabel": "Versión", "glossary": { "title": "Glosario Localizado", "intro": "Los siguientes glosarios proporcionan terminología localizada para el 3D Slicer en español latinoamericano y portugués brasileño.", "viewGlossary": "Ver Glosario" }, "langs": { "english": "Inglés", "portugueseBR": "Portugués (BR)", "spanishLA": "Español (América Latina)" } },
      "tutorialCollection": {
        "pageTitle": "Colección Slicer Tutorial Maker",
        "intro": "La <strong>Colección Slicer Tutorial Maker</strong> es un conjunto seleccionado de tutoriales creados con la extensión <a href=\"https://github.com/SoniaPujolLab/SlicerTutorialMaker\" class=\"hyperlink\" target=\"_blank\">Slicer Tutorial Maker</a>. Cada tutorial se genera automáticamente ejecutando un script de Python dentro del 3D Slicer, que captura capturas de pantalla anotadas y produce resultados en formatos HTML, PDF y Markdown. Los tutoriales están disponibles en múltiples idiomas y sirven tanto como recursos de aprendizaje como implementaciones de referencia para autores que crean nuevos tutoriales.",
        "loading": "Cargando\u2026", "noLanguages": "No hay idiomas disponibles.", "viewOnGitHub": "Ver en GitHub",
        "cards": { "welcome": { "title": "Tutorial de Bienvenida", "li1": "Introducción a la interfaz del 3D Slicer", "li2": "Carga y exploración de datos de muestra", "li3": "Navegación en vistas 3D y 2D", "li4": "Punto de partida ideal para usuarios nuevos" }, "fourMinute": { "title": "Tutorial de Cuatro Minutos", "li1": "Descripción general rápida de las funciones principales de Slicer", "li2": "Carga de datos y visualización básica", "li3": "Interacción básica con el usuario", "li4": "Comienza en menos de 4 minutos" }, "aiSegmentation": { "title": "Segmentación Basada en IA en 3D Slicer", "li1": "Segmentación anatómica con IA", "li2": "Carga y procesamiento de datos DICOM", "li3": "Generación de modelos de segmentación 3D", "li4": "Flujo de trabajo completo de principio a fin" }, "visualization": { "title": "Tutorial de Carga de Datos y Visualización 3D", "li1": "Visualización 3D interactiva", "li2": "Recorte interactivo de datos", "li3": "Manipulación interactiva del viewport", "li4": "Presentación de datos de imágenes médicas" } }
      },
